const schedule = [
  { start: '10:35', end: '10:50', segment: 'Pre-service Prayer', anchor: 'CCW', duration: 15 },
  { start: '11:00', end: '11:05', segment: 'Opening Prayer & Confessions', anchor: 'Ashim', duration: 5 },
  { start: '11:05', end: '11:20', segment: 'Praise & Worship', anchor: 'CCW', duration: 15 },
  { start: '11:20', end: '11:35', segment: 'Second Prayer & Confessions', anchor: 'Dami and Precious', duration: 15 },
  { start: '11:35', end: '11:40', segment: 'Testimony', anchor: 'Precious', duration: 5 },
  { start: '11:40', end: '11:50', segment: 'Choir Ministration', anchor: 'CCW', duration: 10 },
  { start: '11:50', end: '13:10', segment: 'Sermon, Tithe & Offering, First Timers, Second Timers, Benediction, Announcements', anchor: 'Pastor Pelumi Kumuyi', duration: 80 }
];

function timeToMinutes(t) {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}

function toTimeStr(mins) {
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  const p = h >= 12 ? 'PM' : 'AM';
  const h12 = h > 12 ? h - 12 : (h === 0 ? 12 : h);
  return `${h12}:${m.toString().padStart(2, '0')} ${p}`;
}

function bar(pct, len = 20) {
  const f = Math.round(pct / 100 * len);
  return '█'.repeat(f) + '░'.repeat(len - f) + ` ${Math.round(pct)}%`;
}

const now = new Date();
const cur = now.getHours() * 60 + now.getMinutes();
let out = '';

if (cur < timeToMinutes('10:35')) {
  const wait = timeToMinutes('10:35') - cur;
  out = `STATUS: Before Service\n`;
  out += `Service has not started yet.\n`;
  out += `Pre-service prayer begins in ${wait} minutes (at 10:35 AM).\n`;
  out += `Main service starts at 11:00 AM.\n`;
  out += `First up: Pre-service Prayer led by CCW.`;
} else if (cur >= timeToMinutes('13:10')) {
  out = `STATUS: Service Ended\n`;
  out += `Today's service has concluded.\n`;
  out += `Total main service duration: 2 hours 10 minutes.\n`;
  out += `God bless everyone!`;
} else {
  let found = false;
  for (let i = 0; i < schedule.length; i++) {
    const seg = schedule[i];
    const s = timeToMinutes(seg.start);
    const e = timeToMinutes(seg.end);
    if (cur >= s && cur < e) {
      found = true;
      const elapsed = cur - s;
      const remaining = e - cur;
      const pct = (elapsed / seg.duration) * 100;
      out = `STATUS: Active — Segment ${i + 1} of ${schedule.length}\n`;
      out += `Segment: ${seg.segment}\n`;
      out += `Anchor: ${seg.anchor}\n`;
      out += `Time Window: ${seg.start} - ${seg.end} (${seg.duration} min total)\n`;
      out += `Elapsed: ${elapsed} min | Remaining: ${remaining} min\n`;
      out += `Progress: ${bar(pct)}\n`;
      if (remaining <= 2) {
        out += `\nURGENT: Only ${remaining} minute(s) left! Prepare for transition immediately!\n`;
      } else if (remaining <= 5) {
        out += `\nHEADS UP: ${remaining} minutes remaining. Start preparing for the next segment.\n`;
      }
      if (i < schedule.length - 1) {
        const next = schedule[i + 1];
        const gap = timeToMinutes(next.start) - e;
        if (gap > 0) {
          out += `\nNext Up (in ${remaining + gap} min, after ${gap} min break):\n`;
        } else {
          out += `\nNext Up (in ${remaining} min):\n`;
        }
        out += `Segment: ${next.segment}\n`;
        out += `Anchor: ${next.anchor}\n`;
        out += `Time: ${next.start} - ${next.end} (${next.duration} min)`;
      } else {
        out += `\nThis is the FINAL segment of the service.`;
      }
      break;
    }
    if (i < schedule.length - 1) {
      const e2 = timeToMinutes(seg.end);
      const ns = timeToMinutes(schedule[i + 1].start);
      if (cur >= e2 && cur < ns) {
        found = true;
        const wait = ns - cur;
        const next = schedule[i + 1];
        out = `STATUS: Transition / Break\n`;
        out += `Just completed: ${seg.segment} (${seg.anchor})\n`;
        out += `\nNext segment starts in ${wait} minute(s):\n`;
        out += `Segment: ${next.segment}\n`;
        out += `Anchor: ${next.anchor}\n`;
        out += `Starts at: ${next.start}`;
        break;
      }
    }
  }
  if (!found) {
    out = 'Could not determine current segment. The current time may be outside the service window.';
  }
  const mainStart = timeToMinutes('11:00');
  const mainEnd = timeToMinutes('13:10');
  if (cur >= mainStart && cur < mainEnd) {
    const totalEl = cur - mainStart;
    const totalDur = mainEnd - mainStart;
    const oPct = Math.min((totalEl / totalDur) * 100, 100);
    out += `\n\nOverall Service Progress:\n`;
    out += `${bar(oPct)}\n`;
    out += `Current Time: ${toTimeStr(cur)} | Service Ends: 1:10 PM`;
  }
}

return out;

