const schedule = [
  { start: '10:35', end: '10:50', segment: 'Pre-service Prayer', anchor: 'CCW', duration: 15 },
  { start: '11:00', end: '11:05', segment: 'Opening Prayer & Confessions', anchor: 'Ashim', duration: 5 },
  { start: '11:05', end: '11:20', segment: 'Praise & Worship', anchor: 'CCW', duration: 15 },
  { start: '11:20', end: '11:35', segment: 'Second Prayer & Confessions', anchor: 'Dami and Precious', duration: 15 },
  { start: '11:35', end: '11:40', segment: 'Testimony', anchor: 'Precious', duration: 5 },
  { start: '11:40', end: '11:50', segment: 'Choir Ministration', anchor: 'CCW', duration: 10 },
  { start: '11:50', end: '13:10', segment: 'Sermon, Tithe & Offering, First Timers, Second Timers, Benediction, Announcements', anchor: 'Pastor Pelumi Kumuyi', duration: 80 }
];

const cues = {
  'Pre-service Prayer': {
    opening: 'Let us gather together in prayer as we prepare our hearts for today\'s service. CCW will lead us in pre-service prayer.',
    closing: 'Pre-service prayer is concluding. Please take your seats as we prepare for the main service. We begin at 11:00 AM.',
    prep: ['Ensure sanctuary seating is ready', 'Sound check all microphones', 'Welcome team positioned at entrance', 'Slides and projector ready for worship lyrics']
  },
  'Opening Prayer & Confessions': {
    opening: 'Good morning, church! Please rise as Ashim leads us in our opening prayer and confessions before the Lord.',
    closing: 'Amen! Thank you, Ashim. Let us now transition into a powerful time of praise and worship!',
    prep: ['Worship team on standby', 'Instruments tuned and ready', 'Worship lyrics loaded on screen']
  },
  'Praise & Worship': {
    opening: 'Let us stand together and lift our voices to the Lord! CCW will lead us in praise and worship.',
    closing: 'What a glorious time of worship! Please remain standing as we move into a season of deeper prayer.',
    prep: ['Prayer team ready', 'Dami and Precious on standby', 'Lower music gradually for smooth transition']
  },
  'Second Prayer & Confessions': {
    opening: 'Let us bow our heads and open our hearts. Dami and Precious will lead us in prayer and confessions.',
    closing: 'Amen! Thank you, Dami and Precious. The Lord has heard our prayers today.',
    prep: ['Precious ready for testimony', 'Testimony microphone prepared', 'Congregation may be seated']
  },
  'Testimony': {
    opening: 'It\'s time to hear what God has been doing! Precious will share a testimony of God\'s faithfulness.',
    closing: 'Glory to God! What a powerful testimony. Thank you, Precious!',
    prep: ['Choir assembling in position', 'Choir microphones and monitors ready', 'Music sheets distributed']
  },
  'Choir Ministration': {
    opening: 'The choir will now minister to us in song. Let\'s receive this ministration with open hearts. CCW, take it away!',
    closing: 'Beautiful ministration! Thank you, choir. Let us now prepare to receive the Word of God.',
    prep: ['Pulpit and Bible ready for Pastor', 'Pastor\'s microphone checked', 'Sermon slides loaded if applicable', 'Offering baskets prepared and positioned']
  },
  'Sermon, Tithe & Offering, First Timers, Second Timers, Benediction, Announcements': {
    opening: 'Please be seated. It is time to receive the Word of God. Pastor Pelumi Kumuyi will now minister to us.',
    closing: 'What a blessed service! Go forth in the name of the Lord. Have a wonderful and blessed week ahead!',
    prep: ['Offering baskets ready for collection', 'First-timer and second-timer welcome cards prepared', 'Announcement slides queued', 'Closing prayer team ready']
  }
};

function timeToMinutes(t) {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}

const now = new Date();
const cur = now.getHours() * 60 + now.getMinutes();
let out = '';

if (cur < timeToMinutes('10:35')) {
  out = `PRE-SERVICE PREPARATION\n\n`;
  out += `The service has not started yet.\n\n`;
  out += `OPENING ANNOUNCEMENT (for 10:35 AM):\n`;
  out += `"${cues['Pre-service Prayer'].opening}"\n\n`;
  out += `PREPARATION CHECKLIST:\n`;
  cues['Pre-service Prayer'].prep.forEach(p => { out += `  [ ] ${p}\n`; });
  out += `\nEnsure all anchors are present:\n- Ashim\n- CCW\n- Dami & Precious\n- Precious\n- Pastor Pelumi Kumuyi`;
} else if (cur >= timeToMinutes('13:10')) {
  out = `POST-SERVICE\n\n`;
  out += `CLOSING WORDS:\n`;
  out += `"${cues['Sermon, Tithe & Offering, First Timers, Second Timers, Benediction, Announcements'].closing}"\n\n`;
  out += `Thank you to all who served today:\n`;
  out += `- Ashim (Opening Prayer & Confessions)\n`;
  out += `- CCW (Pre-service Prayer, Praise & Worship, Choir Ministration)\n`;
  out += `- Dami & Precious (Second Prayer & Confessions)\n`;
  out += `- Precious (Testimony)\n`;
  out += `- Pastor Pelumi Kumuyi (Sermon & Closing)`;
} else {
  let currentSeg = null;
  let nextSeg = null;
  for (let i = 0; i < schedule.length; i++) {
    const s = timeToMinutes(schedule[i].start);
    const e = timeToMinutes(schedule[i].end);
    if (cur >= s && cur < e) {
      currentSeg = schedule[i];
      if (i < schedule.length - 1) nextSeg = schedule[i + 1];
      break;
    }
    if (i < schedule.length - 1) {
      const ns = timeToMinutes(schedule[i + 1].start);
      if (cur >= e && cur < ns) {
        nextSeg = schedule[i + 1];
        break;
      }
    }
  }
  if (currentSeg) {
    const remaining = timeToMinutes(currentSeg.end) - cur;
    const c = cues[currentSeg.segment];
    out = `TRANSITION CUES — ${currentSeg.segment}\n`;
    out += `Anchor: ${currentSeg.anchor} | ${remaining} min remaining\n\n`;
    out += `OPENING CUE (already delivered):\n"${c.opening}"\n\n`;
    if (remaining <= 5) {
      out += `>>> CLOSING CUE (use NOW — ${remaining} min left):\n"${c.closing}"\n\n`;
    } else {
      out += `CLOSING CUE (use when segment ends):\n"${c.closing}"\n\n`;
    }
    if (nextSeg) {
      const nc = cues[nextSeg.segment];
      out += `NEXT SEGMENT INTRODUCTION:\n"${nc.opening}"\n\n`;
      out += `PREPARATION CHECKLIST for ${nextSeg.segment}:\n`;
      nc.prep.forEach(p => { out += `  [ ] ${p}\n`; });
    }
  } else if (nextSeg) {
    const nc = cues[nextSeg.segment];
    const wait = timeToMinutes(nextSeg.start) - cur;
    out = `IN TRANSITION — Next segment in ${wait} min\n\n`;
    out += `INTRODUCTION CUE:\n"${nc.opening}"\n\n`;
    out += `PREPARATION CHECKLIST:\n`;
    nc.prep.forEach(p => { out += `  [ ] ${p}\n`; });
  } else {
    out = 'Could not determine current position in the service schedule.';
  }
}

return out;
